module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

localparam PULSE_STATE_0 = 2'b00;
localparam PULSE_STATE_1 = 2'b01;
localparam PULSE_STATE_2 = 2'b10;
localparam PULSE_STATE_3 = 2'b11;

reg [1:0] pulse_state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        pulse_state <= PULSE_STATE_0;
        data_out <= 1'b0;
    end else begin
        case (pulse_state)
            PULSE_STATE_0: begin
                if (data_in == 1'b1) begin
                    pulse_state <= PULSE_STATE_1;
                end else begin
                    pulse_state <= PULSE_STATE_0;
                end
            end
            PULSE_STATE_1: begin
                if (data_in == 1'b0) begin
                    pulse_state <= PULSE_STATE_2;
                end else begin
                    pulse_state <= PULSE_STATE_1;
                end
            end
            PULSE_STATE_2: begin
                if (data_in == 1'b1) begin
                    pulse_state <= PULSE_STATE_3;
                end else begin
                    pulse_state <= PULSE_STATE_1;
                end
            end
            PULSE_STATE_3: begin
                data_out <= 1'b1;
                pulse_state <= PULSE_STATE_0;
            end
        endcase
    end
end

endmodule
